import { getAxisRotated } from '../../axis/axisutils';

export function addProcessorPolyfills(processor) {
    var proto = processor.prototype;

    // Available polyfills
    var polyfills = {
        getAxisRotated: function() {
            return getAxisRotated(this.data);
        },
        isstacked: function() {
            return false;
        }
    };

    // Apply polyfills if method not present
    for (var method in polyfills) {
        if (!proto[method]) {
            proto[method] = polyfills[method];
        }
    }
}
